mapper.select:

select id,
	   first_name ,
	   last_name ,
	   age,
	   create_time,
	   update_time
	   from student
	   where 1=1 

	   and id=#{id}


	   and 
	   (first_name LIKE #{condition}
	   OR last_name LIKE #{condition}
	   )


	   and age=#{age}


	   AND create_time > #{startDate}
	   AND update_time > #{startDate}


	   AND  create_time < #{endDate}
	   AND  update_time < #{endDate}

	   ORDER BY ${sort} ${orderBy}
